module RefModule(
    input CLK, RST,
    input UD1, LD1, input [7:0] LOAD_IN1, output reg [7:0] Q1,
    input UD2, LD2, input [7:0] LOAD_IN2, output reg [7:0] Q2,
    output [7:0] sum
);reg [7:0] count1, count2;

always @(posedge CLK) begin
    if (RST) begin
        count1 <= 8'b0;
        count2 <= 8'b0;
    end else begin
        if (UD1) begin
            count1 <= count1 + 1;
        end else begin
            count1 <= count1 - 1;
        end

        if (UD2) begin
            count2 <= count2 + 1;
        end else begin
            count2 <= count2 - 1;
        end

        if (LD1) begin
            count1 <= LOAD_IN1;
        end

        if (LD2) begin
            count2 <= LOAD_IN2;
        end
    end
end

  wire _n01 = count1[0] ^ count2[0];
  wire _c01 = count1[0] & count2[0];
  wire _n02 = count1[1] ^ count2[1] ^ _c01;
  wire _c02 = (count1[1] & count2[1]) | (count1[1] & _c01) | (count2[1] & _c01);
  wire _n03 = count1[2] ^ count2[2] ^ _c02;
  wire _c03 = (count1[2] & count2[2]) | (count1[2] & _c02) | (count2[2] & _c02);
  wire _n04 = count1[3] ^ count2[3] ^ _c03;
  wire _c04 = (count1[3] & count2[3]) | (count1[3] & _c03) | (count2[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

assign Q1 = count1;
assign Q2 = count2;

endmodule
